{"tool":"sql_query","args":{"query":"WITH eligible AS (
  SELECT rowid AS file_order, lot_id, plant_code, line_id, shift, build_date, battery_health_score_pct, warranty_risk_index, release_status
  FROM production_quality_measurements
  WHERE lower(release_status) <> 'released'
    AND CAST(battery_health_score_pct AS REAL) > 96
    AND CAST(warranty_risk_index AS REAL) < 2.0
), containment AS (
  SELECT * FROM eligible WHERE lower(release_status) = 'containment' ORDER BY file_order LIMIT 1
), hold AS (
  SELECT * FROM eligible WHERE lower(release_status) = 'hold' ORDER BY file_order LIMIT 1
)
SELECT 
  (SELECT COUNT(*) FROM eligible) AS passing_nonreleased_lot_count,
  (SELECT json_object('file_order', file_order, 'lot_id', lot_id, 'plant_code', plant_code, 'line_id', line_id, 'shift', shift, 'build_date', build_date, 'battery_health_score_pct', battery_health_score_pct, 'warranty_risk_index', warranty_risk_index, 'release_status', release_status) FROM containment) AS first_containment_example,
  (SELECT json_object('file_order', file_order, 'lot_id', lot_id, 'plant_code', plant_code, 'line_id', line_id, 'shift', shift, 'build_date', build_date, 'battery_health_score_pct', battery_health_score_pct, 'warranty_risk_index', warranty_risk_index, 'release_status', release_status) FROM hold) AS first_hold_example;"} }
{"answer":"There are 0 non-released lots that still meet the production release thresholds battery_health_score_pct > 96 and warranty_risk_index < 2.0. First containment example in file order: none (no qualifying rows with release_status=containment). First hold example in file order: none (no qualifying rows with release_status=hold). Source rule fields from main.md: release_status must be non-released here, with battery_health_score_pct > 96 and warranty_risk_index < 2.0; lots achieve release_status=released only when battery_health_score_pct exceeds 96% and warranty_risk_index falls below 2.0."}

